import fs from "node:fs";
import { captureFromHook } from "../chatSessions/index.js";
export function readHookStdin() {
    try {
        const raw = fs.readFileSync(0, "utf-8").trim();
        if (!raw) {
            return null;
        }
        return JSON.parse(raw);
    }
    catch {
        return null;
    }
}
export async function runCaptureHook(hookType, agent = "claude-code", preParsedInput, pluginVersion) {
    const input = preParsedInput ?? readHookStdin();
    if (!input?.session_id) {
        return;
    }
    try {
        await captureFromHook(hookType, input, agent, pluginVersion);
    }
    catch {
        // Never crash the host app
    }
}
